const response = $input.first().json;
const content = response.candidates[0].content.parts[0].text;

// Parse the JSON from Gemini response
let script;
try {
  let text = content.trim();
  if (text.startsWith('```')) text = text.split('\n').slice(1).join('\n');
  if (text.endsWith('```')) text = text.slice(0, text.lastIndexOf('```'));
  script = JSON.parse(text);
} catch (e) {
  throw new Error(`Failed to parse Gemini response as JSON: ${e.message}`);
}

// Return each scene as a separate item for the loop
const scenes = script.scenes.map((scene, index) => ({
  json: {
    scene_index: index,
    scene_id: scene.id,
    scene_title: scene.title,
    narration: scene.narration,
    visual_prompt: scene.visual_prompt,
    total_scenes: script.scenes.length,
    youtube_title: script.youtube_title,
    youtube_description: script.youtube_description,
    youtube_tags: script.youtube_tags,
    topic: script.topic
  }
}));

return scenes;
